const row = $('Loop: taller por taller').item.json;
const apiResp = $input.item.json;
const status = apiResp.status || 'UNKNOWN';
const result = apiResp.result || {};

// Siempre actualizar enriched_at para no reintentar lugares eliminados
const parts = ['enriched_at = NOW()'];

function esc(v) {
  if (v === null || v === undefined) return 'NULL';
  if (typeof v === 'number') return String(v);
  if (typeof v === 'object') return "'" + JSON.stringify(v).replace(/'/g, "''") + "'::jsonb";
  return "'" + String(v).replace(/'/g, "''") + "'";
}

if (status === 'OK') {
  const phone = result.formatted_phone_number || null;
  const rating = result.rating != null
    ? Math.round(Number(result.rating) * 10) / 10
    : null;
  const ratingCount = result.user_ratings_total || null;
  const website = result.website || null;

  const openingHours = result.opening_hours ? {
    weekday_text: result.opening_hours.weekday_text || [],
    periods: (result.opening_hours.periods || []).map(function(p) {
      return {
        open:  { day: p.open.day,  time: p.open.time  },
        close: p.close ? { day: p.close.day, time: p.close.time } : null
      };
    })
  } : null;

  const photos = (result.photos || []).slice(0, 2).map(function(p) {
    return p.photo_reference;
  });

  if (phone)              parts.push('phone = '         + esc(phone));
  if (rating !== null)    parts.push('rating = '        + esc(rating));
  if (ratingCount)        parts.push('rating_count = '  + esc(ratingCount));
  if (website)            parts.push('website = '       + esc(website));
  if (openingHours)       parts.push('opening_hours = ' + esc(openingHours));
  if (photos.length > 0)  parts.push('photos = '        + esc(photos));
}

const updateSql = 'UPDATE workshop_locations SET '
  + parts.join(', ')
  + ' WHERE id = ' + String(row.id);

return [{ json: { id: row.id, name: row.name, updateSql: updateSql, status: status } }];
